var listTypeLamp = ["D_CCT-RGB_BLE"]
// Parse int an toàn
function toInt(v, def) {
    var n = parseInt(v, 10);
    return isNaN(n) ? def : n;
}
// Button counter
function handleButtonCounter(msg, metadata, newMsg) {
    for (var key in msg) {
        if (!msg.hasOwnProperty(key)) continue;
        if (key.indexOf("bt") !== 0) continue;
        if (metadata[key] === undefined) continue;

        if (msg[key] !== metadata[key]) {
            var counterKey = (key === "bt")
                ? "countBt"
                : "count" + key.charAt(0).toUpperCase() + key.slice(1);

            var count = toInt(metadata[counterKey], 0) + 1;
            newMsg[counterKey] = count;

            if (count >= toInt(metadata.ss_longevityRelay, 100000)) {
                metadata.alarmAction = "addAlarm";
                metadata.key_alarmType = "Hết tuổi thọ nút số " + counterKey;
                metadata.key_alarmSeverity = "WARNING";// CRITICAL, MAJOR, MINOR, WARNING, INDETERMINATE
            }
        }
    }
}
//Rule tăng counter
function handleOnoffCounter(msg, metadata, newMsg) {
    if (msg.onoff === undefined || metadata.onoff === undefined) {
        return;
    }

    if (msg.onoff !== metadata.onoff) {
        var count = toInt(metadata.countOnoff, 0) + 1;
        newMsg.countOnoff = count;

        if (count >= toInt(metadata.ss_longevityOnoff, 50000)) {
            metadata.alarmAction = "addAlarm";
            metadata.key_alarmType = "Hết tuổi thọ bật/tắt đèn";
            metadata.key_alarmSeverity = "WARNING";// CRITICAL, MAJOR, MINOR, WARNING, INDETERMINATE
        }
    }
}
//Lamp usageTime (chỉ cho lamp)
function handleLampUsage(msg, metadata, newMsg, listTypeLamp) {
    if (listTypeLamp.indexOf(metadata.cs_type) === -1) return;
    if (msg.onoff === undefined || metadata.onoff === undefined) return;

    var curr = toInt(msg.onoff, -1);
    var prev = toInt(metadata.onoff, -1);
    var ts = toInt(msg.ts, 0);

    if (curr < 0 || prev < 0 || ts === 0) return;

    var usage = toInt(metadata.usageTime, 0);
    var lastOn = toInt(metadata.lastOnTime, 0);

    // 1 → 0
    if (prev === 1 && curr === 0 && lastOn > 0) {
        var delta = ts - lastOn;
        if (delta > 0) usage += delta;
        newMsg.usageTime = usage;

        if (usage >= toInt(metadata.ss_longevityLamp, 30000*60*60*1000)) {
            metadata.alarmAction = "addAlarm";
            metadata.key_alarmType = "Hết tuổi thọ của đèn";
            metadata.key_alarmSeverity = "WARNING";// CRITICAL, MAJOR, MINOR, WARNING, INDETERMINATE
        }
    }

    // 0 → 1
    if (prev === 0 && curr === 1) {
        newMsg.lastOnTime = ts;
    }
}

// PIR – Motion detection
function handlePirAlarm(msg, metadata) {
    if (msg.pir === undefined) return;

    var pir = toInt(msg.pir, -1);
    if (pir < 0) return;

    // Có chuyển động
    if (pir === 1) {
        metadata.alarmAction = "addAlarm";
        metadata.key_alarmType = "Phát hiện có chuyển động";
        metadata.key_alarmSeverity = "WARNING";
    }

    // Không còn chuyển động
    if (pir === 0) {
        metadata.alarmAction = "delAlarm";
        metadata.key_alarmType = "Phát hiện có chuyển động";
    }
}

//Connectivity – ÁP DỤNG CHO MỌI THIẾT BỊ
function handleConnectivity(msg, metadata, newMsg) {
    if (msg.stt === undefined || metadata.stt === undefined) return;

    var curr = toInt(msg.stt, -1);
    var prev = toInt(metadata.stt, -1);
    var ts = toInt(msg.ts, 0);

    if (curr < 0 || prev < 0 || ts === 0) return;

    var currOnoff = toInt(msg.onoff, 0);
    var usage = toInt(metadata.usageTime, 0);
    var lastOn = toInt(metadata.lastOnTime, 0);

    // ONLINE → OFFLINE
    if (prev === 1 && curr === 0) {
        metadata.alarmAction = "addAlarm";
        metadata.key_alarmType = "Thiết bị offline";
        metadata.key_alarmSeverity = "WARNING";// CRITICAL, MAJOR, MINOR, WARNING, INDETERMINATE

        if (currOnoff === 1 && lastOn > 0) {
            var delta = ts - lastOn;
            if (delta > 0) usage += delta;
            newMsg.usageTime = usage;
        }
    }

    // OFFLINE → ONLINE
    if (prev === 0 && curr === 1) {
        metadata.alarmAction = "delAlarm";
        metadata.key_alarmType = "Thiết bị offline";
        if (currOnoff === 1) {
            newMsg.lastOnTime = ts;
        }
    }
}

//processMessage
function processMessage(msg, metadata) {
    var newMsg = {};

    for (var k in msg) {
        if (msg.hasOwnProperty(k) && k !== "ts") {
            newMsg[k] = msg[k];
        }
    }

    handleButtonCounter(msg, metadata, newMsg);
    handleOnoffCounter(msg, metadata, newMsg);
    handleLampUsage(msg, metadata, newMsg, listTypeLamp);
    handlePirAlarm(msg, metadata);
    handleConnectivity(msg, metadata, newMsg);

    return newMsg;
}
msg = processMessage(msg, metadata)
return {
    msg: msg,
    metadata: metadata,
    msgType: msgType
};

